#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 3e4+5;
const int K = (N<<6);
struct Tree{int ls,rs,sum,lmx,rmx;}t[K];
struct qry{int l,r,k;}q[N];
int T,n,m,Q,p[N],a[N],Ans;
int num_cnt,bel[N],node_cnt,Rt[N];
map<int,int> Ls;
vector<int> num[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void push_up(int u){
    t[u].lmx=max(t[t[u].ls].lmx,t[t[u].ls].sum+t[t[u].rs].lmx);
    t[u].rmx=max(t[t[u].rs].rmx,t[t[u].rs].sum+t[t[u].ls].rmx);
    t[u].sum=t[t[u].ls].sum+t[t[u].rs].sum;return;
}
void update(int &u,int l,int r,int p,int k){
    t[++node_cnt]=t[u],u=node_cnt;
    if(l>p||r<p)return;
    if(l==r&&p==l){
        t[u].sum=k;
        if(k>0)t[u].lmx=k,t[u].rmx=k;
        return;
    }int mid=(l+r)>>1;
    update(t[u].ls,l,mid,p,k);
    update(t[u].rs,mid+1,r,p,k);
    push_up(u);return;
}
int query_sum(int u,int l,int r,int L,int R){
    if(r<L||R<l)return 0;
    if(L<=l&&r<=R)return t[u].sum;
    int mid=(l+r)>>1,res=0;
    res+=query_sum(t[u].ls,l,mid,L,R);
    res+=query_sum(t[u].rs,mid+1,r,L,R);
    return res;
}
int query_lmx(int u,int l,int r,int L,int R){
    if(r<L||R<l)return 0;
    if(L<=l&&r<=R)return t[u].lmx;
    int mid=(l+r)>>1,res=0;
    res=max(res,query_lmx(t[u].ls,l,mid,L,R));
    res=max(res,query_sum(t[u].ls,l,mid,L,R)+query_lmx(t[u].rs,mid+1,r,L,R));
    return res;
}
int query_rmx(int u,int l,int r,int L,int R){
    if(r<L||R<l)return 0;
    if(L<=l&&r<=R)return t[u].rmx;
    int mid=(l+r)>>1,res=0;
    res=max(res,query_rmx(t[u].rs,mid+1,r,L,R));
    res=max(res,query_sum(t[u].rs,mid+1,r,L,R)+query_rmx(t[u].ls,l,mid,L,R));
    return res;
}
int main(){
    n=read();
    for(int i=1;i<=n;i++)
        a[i]=read(),Ls[a[i]]=0;
    Q=read();
    for(auto &u:Ls)u.se=(++num_cnt),bel[u.se]=u.fr;
    for(int i=1;i<=n;i++)
        a[i]=Ls[a[i]],num[a[i]].pb(i);
    for(int i=1;i<=n;i++)
        update(Rt[num_cnt+1],1,n,i,-1);
    for(int i=num_cnt;i>=1;i--){
        Rt[i]=Rt[i+1];
        for(int x:num[i])update(Rt[i],1,n,x,1);
    }while(Q--){
        int a=read(),b=read(),c=read(),d=read();
        int tmp[4]={(a+Ans)%n,(b+Ans)%n,(c+Ans)%n,(d+Ans)%n};
        sort(tmp,tmp+4);
        a=tmp[0]+1,b=tmp[1]+1,c=tmp[2]+1,d=tmp[3]+1;
        int l=1,r=num_cnt,res=1;
        while(l<=r){
            int mid=(l+r)>>1;
            int tsum=query_sum(Rt[mid],1,n,b,c);
            int trmx=query_rmx(Rt[mid],1,n,a,b-1);
            int tlmx=query_lmx(Rt[mid],1,n,c+1,d);
            int tans=tsum+tlmx+trmx;
            if(tans>=0)res=mid,l=mid+1;else r=mid-1;
        }Ans=bel[res];cout<<Ans<<"\n";
    }
    return 0;
}
